async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    await browser.navigateTo('https://www.instacart.com/');
    await browser.awaitPageLoad();

    const searchInput = await browser.extractComponent<{ cssSelector: string; submitButtonCssSelector: string }>({
        typeName: 'SearchInput',
        schema: '{ cssSelector: string; submitButtonCssSelector: string; }'
    });
    if (!searchInput || !searchInput.cssSelector) {
        throw new Error('Could not find search input');
    }
    await browser.clearAndType(searchInput.cssSelector, 'recipes: ' + params.recipeName);
    if (searchInput.submitButtonCssSelector) {
        await browser.clickAndWait(searchInput.submitButtonCssSelector);
    } else {
        await browser.pressKey('Enter');
        await browser.awaitPageLoad();
    }

    const recipe = await browser.extractComponent<{ name: string; detailsLinkSelector: string }>({
        typeName: 'RecipeInfo',
        schema: '{ name: string; subtitle: string; detailsLinkSelector: string; }'
    }, params.recipeName);
    if (!recipe || !recipe.detailsLinkSelector) {
        throw new Error('Could not find recipe: ' + params.recipeName);
    }
    await browser.clickAndWait(recipe.detailsLinkSelector);

    const hero = await browser.extractComponent<{ recipeName: string; addAllIngredientsSelector: string; ingredients: { name: string; price: string; addToCartButtonSelector?: string }[] }>({
        typeName: 'RecipeHeroSection',
        schema: '{ recipeName: string; summary: string; addAllIngredientsSelector: string; saveButtonSelector: string; ingredients: { name: string; price: string; addToCartButtonSelector?: string; }[]; }'
    });
    if (!hero || !hero.addAllIngredientsSelector) {
        throw new Error('Could not find recipe details for: ' + params.recipeName);
    }
    await browser.clickAndWait(hero.addAllIngredientsSelector);
    const count = hero.ingredients ? hero.ingredients.length : 0;
    return { success: true, message: 'Added ' + count + ' ingredients from "' + hero.recipeName + '" to cart' };
}
